<?phpnamespace app\module\User;//导入部分use app\dep\AddressDep;use app\dep\User\PermissionDep;use app\dep\User\RoleDep;use app\dep\User\UsersDep;use app\dep\User\UsersTokenDep;use app\enum\CommonEnum;use app\enum\EmailEnum;use app\module\BaseModule;use app\service\DictService;use Carbon\Carbon;use support\Cache;use Webman\RedisQueue\Redis;class UsersModule extends BaseModule{    public $UserDep;    public $UserTokenDep;    public $RoleDep;    public $PermissionDep;    public $AddressDep;    public function __construct()    {        $this->UserDep = new UsersDep();        $this->UserTokenDep = new UsersTokenDep();        $this->RoleDep = new RoleDep();        $this->PermissionDep = new PermissionDep();        $this->AddressDep = new AddressDep();       }    public function register($request)    {        $param = $request->all();        $dep = $this->UserDep;        $tokenDep = $this->UserTokenDep;        if (empty($param['email']) || empty($param['password']) || empty($param['respassword'])            || empty($param['code']) || empty($param['username'])        ) {            return self::response([], '必填项不能为空', 100);        }        // 用 MD5 生成安全的缓存 key        $cacheKey = 'email_code_' . md5($param['email']);        $code = Cache::get($cacheKey);        if ($code != $param['code']) {            return self::response([], '验证码错误', 100);        }        $resdep = $dep->firstByEmail($param['email']);        if ($resdep) {            return self::response([], '邮箱已存在', 100);        }        if ($param['password'] != $param['respassword']) {            return self::response([], '密码不一致', 100);        }        // 创建随机 token        $token = md5(uniqid(rand(), true));        // 设置 token 过期时间，一周后        $expire_time = Carbon::now()->addWeek()->toDateTimeString();        $data = [            'email'    => $param['email'],            'password' => password_hash($param['password'], PASSWORD_DEFAULT),            'username' => $param['username'],        ];        $userId = $dep->add($data);        $tokenData = [            'user_id'    => $userId,            'token'      => $token,            'expires_in' => $expire_time,            'ip'         => $request->getRealIp(),        ];        $tokenDep->add($tokenData);        $data1 = [            'token' => $token,        ];        return self::response($data1);    }    public function login($request)    {        $param = $request->all();        $dep = $this->UserDep;        $tokenDep = $this->UserTokenDep;        if (            empty($param['email']) || empty($param['password'])        ) {            return self::response([], '必填项不能为空', 100);        }        $resDep = $dep->firstByEmail($param['email']);        if (!$resDep) {            return self::response([], '邮箱不存在', 100);        }        if (!password_verify($param['password'], $resDep['password'])) {            return self::response([], '密码不正确', 100);        }        //创建一个随机token,命名为$token        $token = md5(uniqid(rand(), true));        //创建token过期时间，为创建token的一周        $expire_time = Carbon::now()->addWeek()->toDateTimeString();        $data = [            'token' => $token,            'expires_in' => $expire_time,            'ip' => $request->getRealIp(),        ];        $tokenDep->editByUserId($resDep['id'], $data);        $data1 = [            'token' => $token,        ];        return self::response($data1);    }    public function sendCode($request)    {        $param = $request->all();        if (empty($param['email'])) {            return self::response([], '邮箱不能为空', 100);        }        if (!isValidEmail($param['email'])) {            return self::response([], '邮箱不合法', 100);        }        // 生成验证码        $code = rand(100000, 999999);        // 获取邮件主题，防止状态传值错误，建议加个 isset 判断        $theme = isset(EmailEnum::$statusArr[$param['status']]) ? EmailEnum::$statusArr[$param['status']] : '默认主题';        $queue = "email-send";        $data = [            'email' => $param['email'],            'theme' => $theme,            'code' => $code,        ];        Redis::send($queue, $data);        // 使用 MD5 对 email 进行哈希，保证缓存 key 中没有特殊字符        $cacheKey = 'email_code_' . md5($param['email']);        // 设置验证码缓存，5 分钟有效，300 秒        Cache::set($cacheKey, $code, 300);        return self::response([], '验证码发送成功');    }    public function forgetPassword($request)    {        $param = $request->all();        $dep = $this->UserDep;        if (empty($param['email']) || empty($param['newpassword'])            || empty($param['code'])        ) {            return self::response([], '必填项不能为空', 100);        }        // 用 MD5 生成缓存 key，保持与 sendCode 中一致        $cacheKey = 'email_code_' . md5($param['email']);        $code = Cache::get($cacheKey);        if ($code != $param['code']) {            return self::response([], '验证码错误', 100);        }        $resdep = $dep->firstByEmail($param['email']);        $data = [            'password' => password_hash($param['newpassword'], PASSWORD_DEFAULT),        ];        $dep->edit($resdep->id, $data);        return self::response();    }    public function init($request)    {        $user = $request->user();        $RoleDep = $this->RoleDep;        $PermissionDep = $this->PermissionDep;        if (!$user) {            return self::response([], '用户不存在', 100);        }        $data = [            'user_id' => $user->id,            'username' => $user->username,            'avatar'   => $user->avatar,        ];        // 获取角色信息及权限 ID 列表（假设存储的是二维数组）        $resRole = $RoleDep->first($user->role_id);        $permissionIdsGroup = json_decode($resRole->permission_id, true); // 转换成数组        if (!$permissionIdsGroup) {            $data['permissions'] = [];            return self::response($data);        }        // 合并二维数组为一维数组，并去重        $flattened = [];        foreach ($permissionIdsGroup as $group) {            if (!empty($group)) {                $flattened = array_merge($flattened, $group);            }        }        $uniquePermissionIds = array_unique($flattened);        // 根据权限 ID 列表查询所有的权限详细数据        $permissions = $PermissionDep->getPermissionsByIds($uniquePermissionIds);        // 使用递归构建权限树，顶级菜单的 parent_id 为 -1        $tree = $this->buildPermissionTree($permissions, -1);        // 构造路由信息（保持原有逻辑不变）        $resRouter = $PermissionDep->getByRouter($uniquePermissionIds);        $router = [];        foreach ($resRouter as $route) {            $router[] = [                'name'      => $route->path,                'path'      => $route->path,                'component' => $route->component,                'meta'      => [                    'menuId' => (string)$route->id,                ],            ];        }        $data['router'] = $router;        $data['permissions'] = $tree;        return self::response($data);    }    /**     * 递归构建权限树     *     * @param array $permissions 所有权限的数组记录，每个记录应包含 id, name, path, icon, parent_id 等字段     * @param mixed $parentId    当前递归查找的父节点 ID，顶级节点为 -1     * @return array             构建完成的权限树     */    private function buildPermissionTree(array $permissions, $parentId)    {        $branch = [];        foreach ($permissions as $permission) {            if ($permission['parent_id'] == $parentId) {                // 递归查找此权限下的子权限                $children = $this->buildPermissionTree($permissions, $permission['id']);                $node = [                    'index' => (string) $permission['id'],                    'label' => $permission['name'],                    'path'  => $permission['path'] ?? '',                    'icon'  => $permission['icon'] ?? '',                ];                if (!empty($children)) {                    $node['children'] = $children;                }                $branch[] = $node;            }        }        return $branch;    }    public function initPersonal($request)    {        $dictService = new DictService();        $RoleDep = $this->RoleDep;        $user = $request->user();        $resRole = $RoleDep->first($user->role_id);        $data['list'] = [            'username' => $user->username,            'email' => $user->email,            'avatar' => $user->avatar,            'phone' => $user->phone,            'role_id' => $user->role_id,            'role_name' => $resRole['name'],            'address' => json_decode($user->address),            'detail_address' => $user->detail_address,            'sex' => $user->sex,            'desc' => $user->desc,        ];        $dict = $dictService            ->setAuthAdressTree()            ->getDict();        $data['dict'] = $dict;        return self::response($data);    }    public function editPersonal($request)    {        $param = $request->all();        $dep = $this->UserDep;        $user = $request->user();        if (empty($param['username'])        ) {            return self::response([], '必填项不能为空', 100);        }        // 验证手机号        if (isset($param['phone']) && !is_valid_phone_number($param['phone'])) {            return self::response([], '无效的手机号码', 100);        }        $data = [            'username' => $param['username'],            'avatar' => $param['avatar'],            'phone' => $param['phone']??'',            'sex' => $param['sex'],            'address' => json_encode($param['address']),            'detail_address' => $param['detail_address']??'',            'desc' => $param['desc'],        ];        $dep->edit($user->id, $data);        return self::response();    }    public function EditPassword($request)    {        $param = $request->all();        $dep = $this->UserDep;        $user = $request->user();        // 检查必填项是否为空        if (empty($param['password']) || empty($param['newpassword']) || empty($param['respassword'])) {            return self::response([], '必填项不能为空', 100);        }        // 验证原密码是否正确        if (!password_verify($param['password'], $user->password)) {            return self::response([], '原密码不正确', 100);        }        // 确保新密码与确认密码一致        if ($param['newpassword'] !== $param['respassword']) {            return self::response([], '新密码不一致', 100);        }        // 防止新密码与原密码相同        if (password_verify($param['newpassword'], $user->password)) {            return self::response([], '新密码不能与原密码一致', 100);        }        // 加密新密码        $data = [            'password' => password_hash($param['newpassword'], PASSWORD_DEFAULT),        ];        // 更新密码        $dep->edit($user->id, $data);        return self::response([], '密码修改成功', 200);    }    public function initList()    {        $dictService = new DictService();        $dict = $dictService            ->setRoleArr()            ->setAuthAdressTree()            ->getDict();        $data['dict'] = $dict;        return self::response($data);    }    public function editList($request)    {        $param = $request->all();        $dep = $this->UserDep;        if (empty($param['username'])) {            return self::response([], '用户名不能为空', 100);        }        $data = [            'username' => $param['username'],            'avatar' => $param['avatar'],            'role_id' => $param['role_id'],            'sex' => $param['sex'],            'address' => json_encode($param['address'])??'[]',            'detail_address' => $param['detail_address']??'',            'desc' => $param['desc'],        ];        $dep->edit($param['id'], $data);        return self::response();    }    public function delList($request)    {        $param = $request->all();        $dep = $this->UserDep;        $dep->del($param['id'], ['is_del' => CommonEnum::YES]);        return self::response();    }    public function listList($request)    {        $dep = $this->UserDep;        $RoleDep = $this->RoleDep;        $AddressDep = $this->AddressDep;        $UserTokenDep = $this->UserTokenDep;        $param = $request->all();        $param['page_size'] = isset($param['page_size']) ? $param['page_size'] : 50;        $param['current_page'] = isset($param['current_page']) ? $param['current_page'] : 1;        $resList = $dep->list($param);        $data['list'] = $resList->map(function ($item) use ($RoleDep, $AddressDep,$UserTokenDep) {            $resRole = $RoleDep->first($item->role_id);            $resUserToken = $UserTokenDep->firstByUserId($item->id);            $addressIDs = json_decode($item->address);            $address = '';            foreach ($addressIDs as $addressID) {                $resAddress = $AddressDep->first($addressID);                $address .= $resAddress->name . '-';            }            $address .= $item->detail_address;            return [                'id' => $item->id,                'uid' => $item->uid,                'username' => $item->username,                'email' => $item->email,                'avatar' => $item->avatar,                'phone' => $item->phone,                'sex' => $item->sex,                'role_id' => $item->role_id,                'desc' => $item->desc,                'role_name' => $resRole->name,                'address_show' => $address,                'address' => json_decode($item->address),                'detail_address' => $item->detail_address,                'expires_in' => $resUserToken->expires_in,                'is_expired' => $resUserToken['expires_in'] < Carbon::now()->toDateTimeString() ? '已过期' : '未过期',                'created_at' => $item['created_at']->toDateTimeString(),            ];        });        $data['page'] = [            'page_size' => $param['page_size'],            'current_page' => $param['current_page'],            'total_page' => $resList->lastPage(),            'total' => $resList->total(),        ];        return self::response($data);    }    public function batchEditList($request)    {        $param = $request->all();        $dep = $this->UserDep;        $id = $param['ids'];        if ($param['field'] == 'sex') {            if (empty($param['sex'])) {                return self::response([], '性别不能为空', 100);            }            $data = [                'sex' => $param['sex'],            ];            $dep->edit($id, $data);        }        if ($param['field'] == 'address') {            if (empty($param['address'])) {                return self::response([], '地址不能为空', 100);            }            $data = [                'address' => json_encode($param['address']),            ];            $dep->edit($id, $data);        }        if ($param['field'] == 'detail_address') {            if (empty($param['detail_address'])) {                return self::response([], '详细地址不能为空', 100);            }            $data = [                'detail_address' => $param['detail_address'],            ];            $dep->edit($id, $data);        }        return self::response();    }    public function userInfo($request)    {        $param = $request->all();        $userDep = $this->UserDep;        $tokenDep = $this->UserTokenDep;        if (empty($param['token'])        ) {            return self::response([], 'token不能为空', 100);        }        $resToken = $tokenDep->firstByToken($param['token']);        $resDep = $userDep->first($resToken['user_id']);        if (!$resDep){            return self::response([], '用户不存在', 100);        }        $data = [            'user_id' => $resDep->id,            'username' => $resDep->username,            'avatar' => $resDep->avatar,        ];        return self::response($data);    }}